def gen(rng, size):
    letters = 'abcdefgh'[:max(2, min(size, 8))]
    pairs = []
    for a in letters:
        for b in letters:
            pairs.append(a + b)
    rng.shuffle(pairs)
    count = rng.randint(len(letters), min(len(pairs), len(letters) * 3))
    words = pairs[:count]
    return [words]

