class Solution:
    def supersequences(self, words):
        letters = set()
        self_loop = set()
        edges = set()
        for w in words:
            a, b = w[0], w[1]
            letters.add(a); letters.add(b)
            if a == b:
                self_loop.add(a)
            else:
                edges.add((a, b))
        letter_list = sorted(letters)
        k = len(letter_list)
        idx = {c: i for i, c in enumerate(letter_list)}
        adj = [[] for _ in range(k)]
        for (a, b) in edges:
            adj[idx[a]].append(idx[b])
        forced = {idx[c] for c in self_loop}

        def has_cycle(keep_set):
            visiting = set()
            visited = set()
            def dfs(u):
                visiting.add(u)
                for v in adj[u]:
                    if v not in keep_set:
                        continue
                    if v in visiting:
                        return True
                    if v not in visited and dfs(v):
                        return True
                visiting.discard(u)
                visited.add(u)
                return False
            for u in keep_set:
                if u not in visited and dfs(u):
                    return True
            return False

        free = [i for i in range(k) if i not in forced]
        best_size = -1
        best_keeps = []
        for m in range(1 << len(free)):
            keep_set = {free[b] for b in range(len(free)) if m & (1 << b)}
            if has_cycle(keep_set):
                continue
            sz = len(keep_set)
            if sz > best_size:
                best_size = sz
                best_keeps = [frozenset(keep_set)]
            elif sz == best_size:
                best_keeps.append(frozenset(keep_set))
        results = []
        for keep in best_keeps:
            freq = [0] * 26
            for c in letter_list:
                i = idx[c]
                pos = ord(c) - 97
                freq[pos] = 1 if i in keep else 2
            results.append(freq)
        results.sort()
        return results

