class Solution:
    def supersequences(self, words):
        letters = set()
        self_loop = set()
        edges = set()
        for w in words:
            a, b = w[0], w[1]
            letters.add(a); letters.add(b)
            if a == b:
                self_loop.add(a)
            else:
                edges.add((a, b))
        letter_list = sorted(letters)
        k = len(letter_list)
        idx = {c: i for i, c in enumerate(letter_list)}
        in_mask = [0] * k
        for (a, b) in edges:
            in_mask[idx[b]] |= (1 << idx[a])
        forced_mask = 0
        for c in self_loop:
            forced_mask |= (1 << idx[c])
        full_mask = (1 << k) - 1
        free_mask = full_mask & ~forced_mask

        def is_acyclic(keep):
            remaining = keep
            while remaining:
                zero_indeg = 0
                m = remaining
                while m:
                    low = m & (-m)
                    v = low.bit_length() - 1
                    if (in_mask[v] & remaining) == 0:
                        zero_indeg |= low
                    m ^= low
                if zero_indeg == 0:
                    return False
                remaining &= ~zero_indeg
            return True

        best_size = -1
        best_masks = []
        sub = free_mask
        while True:
            if is_acyclic(sub):
                sz = bin(sub).count('1')
                if sz > best_size:
                    best_size = sz
                    best_masks = [sub]
                elif sz == best_size:
                    best_masks.append(sub)
            if sub == 0:
                break
            sub = (sub - 1) & free_mask

        results = []
        for keep in best_masks:
            freq = [0] * 26
            for c in letter_list:
                i = idx[c]
                pos = ord(c) - 97
                freq[pos] = 1 if (keep & (1 << i)) else 2
            results.append(freq)
        results.sort()
        return results

