var supersequences = function(words) {
    const letterSet = new Set();
    const selfLoop = new Set();
    const edgeSet = new Set();
    for (const w of words) {
        const a = w[0], b = w[1];
        letterSet.add(a); letterSet.add(b);
        if (a === b) selfLoop.add(a); else edgeSet.add(a + '|' + b);
    }
    const letterList = Array.from(letterSet).sort();
    const k = letterList.length;
    const idx = {};
    letterList.forEach((c, i) => idx[c] = i);
    const inMask = new Array(k).fill(0);
    for (const e of edgeSet) {
        const [a, b] = e.split('|');
        inMask[idx[b]] |= (1 << idx[a]);
    }
    let forcedMask = 0;
    for (const c of selfLoop) forcedMask |= (1 << idx[c]);
    const fullMask = (1 << k) - 1;
    const freeMask = fullMask & ~forcedMask;

    function bitPos(low) {
        let v = 0;
        while (low > 1) { low >>>= 1; v++; }
        return v;
    }
    function isAcyclic(keep) {
        let remaining = keep;
        while (remaining) {
            let zeroIndeg = 0;
            let m = remaining;
            while (m) {
                const low = m & (-m);
                const v = bitPos(low);
                if ((inMask[v] & remaining) === 0) zeroIndeg |= low;
                m ^= low;
            }
            if (zeroIndeg === 0) return false;
            remaining &= ~zeroIndeg;
        }
        return true;
    }

    let bestSize = -1;
    let bestMasks = [];
    let sub = freeMask;
    while (true) {
        if (isAcyclic(sub)) {
            let sz = 0, t = sub;
            while (t) { sz += t & 1; t >>= 1; }
            if (sz > bestSize) { bestSize = sz; bestMasks = [sub]; }
            else if (sz === bestSize) bestMasks.push(sub);
        }
        if (sub === 0) break;
        sub = (sub - 1) & freeMask;
    }

    const results = [];
    for (const keep of bestMasks) {
        const freq = new Array(26).fill(0);
        for (const c of letterList) {
            const i = idx[c];
            const pos = c.charCodeAt(0) - 97;
            freq[pos] = (keep & (1 << i)) ? 1 : 2;
        }
        results.push(freq);
    }
    results.sort((a, b) => {
        const n = Math.min(a.length, b.length);
        for (let i = 0; i < n; i++) if (a[i] !== b[i]) return a[i] - b[i];
        return a.length - b.length;
    });
    return results;
};
